import push from "push.js"

export const SetCurrentChatActionCreator = (chat) => ({
    type: "SET-CURRENT-CHAT",
    chat
})

export const SetChatsListActionCreator = (list) => ({
    type: "SET-CHATS-LIST",
    list
})
export const UpdateChatsActionCreator = (data) => ({
    type: "UPDATE-CHAT-LIST",
    data
})

const makeNotice = (message) => {
    //сделать проверку пользователя
    // if(document.hasFocus()) и текущий чат не с этим юзером
    push.clear();
    push.create("New message", {
        body: message.lastMessage,
        icon: message.otherProfileImage?.url,
        timeout: 4000,
        onClick: () => {
            window.focus();
            this.close();
        }
    })
}

let initialState = {
    CurrentChat: null,
    ChatsList: []
}

const ChatsReducer = (state = initialState, action) => {

    switch (action.type) {
        case "SET-CURRENT-CHAT":
            return {
                ...state,
                CurrentChat: action.chat
            }
        case "SET-CHATS-LIST":
            return {
                ...state,
                ChatsList: action.list
            }
        case "UPDATE-CHAT-LIST":
            let newChatList = state.ChatsList.map(chat => {
                if (chat.id === action.data.id) {
                    makeNotice({
                        ...chat,
                        otherUserName: action.data.otherUserName,
                        lastMessage: action.data.lastMessage,
                        messageStamp: action.data.messageStamp
                    })
                    return {
                        ...chat,
                        lastMessage: action.data.lastMessage,
                        messageStamp: action.data.messageStamp
                    }
                }
                return chat;
            })
            return {
                ...state,
                ChatsList: newChatList
            }
        default:
            return state;
    }
};

export default ChatsReducer;